window.SmartRisk=window.SmartRisk||{};SmartRisk.Sidebar={init(){const e=document.getElementById("app-sidebar");e.innerHTML=`<div class="sidebar-brand"><div class="sidebar-brand-mark">SR</div><div class="sidebar-brand-copy"><h1 class="sidebar-brand-title">SmartRisk CZ5</h1><p class="sidebar-brand-subtitle">Gestión territorial del riesgo</p></div></div><nav class="sidebar-nav">${SmartRisk.Config.navigation.map(i=>`<a class="sidebar-link" data-route="${i.path}" href="#${i.path}"><span class="sidebar-link-icon">${SmartRisk.Icon.render(i.icon,20)}</span><span class="sidebar-link-label">${i.label}</span></a>`).join("")}</nav><div class="sidebar-footer"><div class="sidebar-footer-copy"><strong>${SmartRisk.Constants.APP_VERSION}</strong><br>Núcleo visual institucional</div></div>`;if(innerWidth>860&&SmartRisk.Storage.get("sidebar.collapsed",false))e.classList.add("is-collapsed")},toggle(){const e=document.getElementById("app-sidebar");if(innerWidth<=860)e.classList.toggle("is-mobile-open");else{e.classList.toggle("is-collapsed");SmartRisk.Storage.set("sidebar.collapsed",e.classList.contains("is-collapsed"))}},setActive(p){document.querySelectorAll(".sidebar-link").forEach(a=>a.classList.toggle("is-active",a.dataset.route===p));document.getElementById("app-sidebar").classList.remove("is-mobile-open")}};